typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

bool primo(int num)
{
    if (num < 2)
        return false;
    if (num == 2)
        return true;
    if (!(num & 1))
        return false;
    int i, raiz = sqrt(num);
    for (i = 3; i <= raiz; i += 2)
    {
        if (num % i == 0)
            return false;
    }
    return true;
}

void valido(int num, vector<int>& memory)
{
    int i, soma;

    soma = 1;

    for (i = 2; i * i <= num; i++)
    {
        if (num % i == 0)
        {
            if (i * i == num)
                soma += i;

            else
                soma += i + num / i;
        }
    }

    memory[num] = primo(soma);
}

int main()
{
    //_
    int a, b, i, j, max, k;
    cin >> a >> b;
    vector<int> validos;
    validos.reserve(b);
    validos[1] = false;
    validos[2] = false;
    validos[3] = false;
    max = b - a - 2;
    bool possivel = false;
    for (i = a + 1; i < b; i++)
        valido(i, validos);
    for (k = 1; k <= max; k++)
    {
        for (i = a + 1; i < b; i++)
        {
            j = i + k;
            if (j >= b)
                break;
            if (validos[i] && validos[j])
            {
                possivel = true;
                break;
            }
        }
        if (possivel)
            break;
    }

    possivel ? (cout << i << " " << j << '\n') : (cout << "Bazinga\n");

    return 0;
}